480	\section{Affine acyclicity of the {\v C}ech complex}
481	
482	\begin{definition}
483	[Standard affine cover from a spanning family]
484	  \label{def:standard_affine_cover}
485	  \lean{AlgebraicGeometry.Scheme.affineOpenCoverOfSpanRangeEqTop}
486	  \mathlibok
487	  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Cover.Open}).}
488	  Let \(R\) be a commutative ring (so \(R = \Gamma(\operatorname{Spec} R,
489	  \mathcal{O})\)) and let \(s : \iota \to R\) be a family of elements that generate
490	  the unit ideal, \(\operatorname{Ideal.span}(\operatorname{range} s) = \top\). The
491	  \emph{standard affine open cover} of \(\operatorname{Spec} R\) associated with
492	  \(s\) is the affine open cover whose index set is \(\iota\), whose \(i\)-th member
493	  is the basic open \(D(s_i)\), and whose \(i\)-th structure morphism is the map of
494	  affine schemes induced by the localisation homomorphism \(R \to R_{s_i}\); that
495	  is, in Mathlib notation the defining equation
496	  \(\bigl(\text{affineOpenCoverOfSpanRangeEqTop}\bigr)_f\, i =
497	  \operatorname{Spec.map}\bigl(\text{algebraMap}\; R\; (\operatorname{Localization.Away}(s_i))\bigr)\),
498	  so that the sections over the \(i\)-th piece are the \emph{away} localisation
499	  \(R_{s_i} = \operatorname{Localization.Away}(s_i)\) and the geometric piece is
500	  \(D(s_i)\). This is exactly the standard open covering
501	  \(\operatorname{Spec} R = \bigcup_i D(s_i)\) by basic opens, packaged as a single
502	  cover object. It is the spanning-family bundle \((s, hs)\) that the affine
503	  {\v C}ech vanishing of Lemma~\ref{lem:cech_acyclic_affine} is stated over.
504	\end{definition}
